  using NewOrderByType = transpilation::order_by_t<
      TableTupleType, GroupByType,
      typename std::remove_cvref_t<ColTypes>::ColType...>;

  return SelectFrom<TableOrQueryType, AliasType, FieldsType, JoinsType,
