```cpp
#pragma once

#include <optional>
#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>
#include <chrono>
#include <iomanip>
#include <sstream>

namespace query_active_users_posts {

struct User {
  sqlgen::PrimaryKey<int> user_id;
  std::string username;
};

struct Post {
  sqlgen::PrimaryKey<int> post_id;
  int user_id;
  sqlgen::DateTime created_at;
};

struct ActiveUser {
  static constexpr const char* tablename = "ActiveUserView";
  static constexpr bool is_view = true;
  sqlgen::PrimaryKey<int> user_id;
  std::string username;
};

std::vector<ActiveUser> query_active_users_posts() {
    using namespace sqlgen::literals;

    // Connect to the database
    auto conn = sqlgen::sqlite::connect("test_db.sqlite");

    // Create tables
    conn->execute("CREATE TABLE IF NOT EXISTS User (user_id INTEGER PRIMARY KEY, username VARCHAR(50) NOT NULL)");
    conn->execute("CREATE TABLE IF NOT EXISTS Post (post_id INTEGER PRIMARY KEY, user_id INTEGER, created_at DATETIME NOT NULL)");

    // Define date range for 2025 December
    auto date_start = sqlgen::Date{2025, 12, 1};
    auto date_end = sqlgen::Date{2025, 12, 31};

    // Build and execute the query
    auto query = sqlgen::select_from<User, "u">("user_id"_t1, "username"_t1)
               | sqlgen::inner_join<Post, "p">("user_id"_t1 == "user_id"_t2)
               | sqlgen::where("created_at"_t2 >= date_start && "created_at"_t2 <= date_end)
               | sqlgen::to<std::vector<ActiveUser>>;

    return query(conn);
}

}  // namespace query_active_users_posts
```

## Key Implementation Points:

1. **Database Connection**: Uses `sqlgen::sqlite::connect()` to connect to "test_db.sqlite" as specified.

2. **Table Creation**: Creates both User and Post tables using raw SQL execution with `conn->execute()`.

3. **Date Range Handling**: Uses `sqlgen::Date` type to define the 2025 December date range.

4. **Query Construction**: Builds the query using sqlgen's fluent interface:
   - `select_from<User, "u">` starts the query with table alias "u"
   - `inner_join<Post, "p">` joins with Post table using alias "p"
   - `where` clause filters by created_at date range
   - `to<std::vector<ActiveUser>>` specifies the return type

5. **Column References**: Uses sqlgen's literal syntax (`"user_id"_t1`) to reference columns with table aliases.

6. **Return Value**: Returns the result vector directly from the query execution.

The implementation follows sqlgen's principles of using a fluent, type-safe API for database operations while meeting all the specified requirements.

