#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>

namespace transaction_transfer_funds {

struct Account {
  sqlgen::PrimaryKey<int> account_id;
  double balance;
};

bool transfer_funds(int from_account_id, int to_account_id, double amount) {
  // Connect to the database
  auto conn_result = sqlgen::sqlite::connect("test_db.sqlite");
  if (!conn_result) {
    return false;
  }
  auto conn = conn_result.value();

  // Begin transaction
  auto begin_result = conn | sqlgen::begin_transaction;
  if (!begin_result) {
    return false;
  }

  try {
    // Verify sufficient funds in from_account
    auto from_balance_result = (sqlgen::read<double> | sqlgen::where(sqlgen::col<"account_id"> == from_account_id))(conn);
    if (!from_balance_result) {
      conn | sqlgen::rollback;
      return false;
    }
    double from_balance = from_balance_result.value();
    if (from_balance < amount) {
      conn | sqlgen::rollback;
      return false;
    }

    // Deduct from sender
    auto deduct_result = (sqlgen::update<Account>(sqlgen::col<"balance"> - amount) 
                         | sqlgen::where(sqlgen::col<"account_id"> == from_account_id))(conn);
    if (!deduct_result) {
      conn | sqlgen::rollback;
      return false;
    }

    // Add to receiver
    auto add_result = (sqlgen::update<Account>(sqlgen::col<"balance"> + amount) 
                       | sqlgen::where(sqlgen::col<"account_id"> == to_account_id))(conn);
    if (!add_result) {
      conn | sqlgen::rollback;
      return false;
    }

    // Commit transaction
    auto commit_result = conn | sqlgen::commit;
    if (!commit_result) {
      conn | sqlgen::rollback;
      return false;
    }

    return true;

  } catch (...) {
    // Ensure rollback on any exception
    conn | sqlgen::rollback;
    return false;
  }
}

}  // namespace transaction_transfer_funds
```

