#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>
#include <optional>

namespace analyze_social_network {

struct User {
  sqlgen::PrimaryKey<int> user_id;
  std::string username;
};

struct Friendship {
  int user1_id;
  int user2_id;
  sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S"> created_at;
};

struct FriendConnection {
  std::string user1_name;
  std::string user2_name;
};

/**
 * Analyze social network data by creating temporary SQL tables for User and Friendship.
 * Returns: std::vector<FriendConnection>.
 */
std::vector<FriendConnection> analyze_social_network_impl(const std::vector<User>& users, const std::vector<Friendship>& friendships) {
  using namespace sqlgen::literals;

  // Connect to SQLite database
  auto conn = sqlgen::sqlite::connect();

  // Create tables
  conn | sqlgen::create_table<User> | sqlgen::create_table<Friendship>;

  // Insert data
  conn | sqlgen::insert(users) | sqlgen::insert(friendships);

  // Query 1: Mutual friends using SELF-JOIN
  auto mutual_friends_query = sqlgen::select_from<User, "u1">(
      "username"_t1, "username"_t4, sqlgen::count("user_id2"_t2).as<"mutual_friends">)
      | sqlgen::inner_join<Friendship, "f1">("user_id"_t1 == "user_id1"_t2)
      | sqlgen::inner_join<Friendship, "f2">("user_id2"_t2 == "user_id1"_t3)
      | sqlgen::inner_join<User, "u2">("user_id2"_t3 == "user_id"_t4)
      | sqlgen::where("user_id"_t1 < "user_id"_t4 && 
                      sqlgen::exists(sqlgen::select_from<Friendship, "f3">(
                          "user_id1"_t5 == "user_id"_t1 && 
                          "user_id2"_t5 == "user_id"_t4)))
      | sqlgen::group_by("user_id"_t1, "user_id"_t4)
      | sqlgen::having(sqlgen::count("user_id2"_t2) > 0);

  // Query 2: Users with more than average friends using subquery
  auto avg_friends_query = sqlgen::select_from<User, "u">(
      "user_id"_t1, "username"_t1, sqlgen::count("user_id2"_t2).as<"friend_count">)
      | sqlgen::left_join<Friendship, "f">("user_id"_t1 == "user_id1"_t2)
      | sqlgen::group_by("user_id"_t1, "username"_t1)
      | sqlgen::having("friend_count"_t1 > 
          sqlgen::select_from<sqlgen::avg>(sqlgen::count().as<"friend_count">)
          | sqlgen::group_by("user_id1"_t1));

  // Execute queries and process results
  auto mutual_results = conn | mutual_friends_query;
  auto avg_results = conn | avg_results_query;

  // Convert mutual friends results to required format
  std::vector<FriendConnection> connections;
  for (const auto& row : mutual_results) {
    FriendConnection conn;
    conn.user1_name = row["username"_t1];
    conn.user2_name = row["username"_t4];
    connections.push_back(conn);
  }

  return connections;
}

}  // namespace analyze_social_network
```

## Key Implementation Details:

1. **Database Connection**: Uses `sqlgen::sqlite::connect()` to establish connection
2. **Table Creation**: Uses `sqlgen::create_table<User>` and `sqlgen::create_table<Friendship>`
3. **Data Insertion**: Uses `sqlgen::insert(users)` and `sqlgen::insert(friendships)`
4. **SELF-JOIN Query**: Implements mutual friends detection using:
   - Multiple `inner_join` operations
   - `where` clause with `user_id < user_id` condition
   - `exists` subquery for validation
   - `group_by` and `having` for aggregation
5. **Subquery Analysis**: Implements user analysis with more than average friends using:
   - `left_join` for optional relationships
   - Subquery with `avg()` aggregation
6. **Fluent Interface**: Uses the pipe operator `|` throughout to chain operations
7. **Result Processing**: Converts query results to the required `FriendConnection` format

The implementation follows sqlgen's principles of using a fluent, type-safe API with compile-time validation of SQL operations.

