std::vector<UpdatedNote> replace_text_in_notes() {
  using namespace sqlgen::literals;

  // 1. Connect to the database
  auto conn_result = sqlgen::sqlite::connect("test_db.sqlite");
  if (!conn_result) {
    throw std::runtime_error("Failed to connect to database");
  }
  auto conn = *conn_result;

  // 2. Create update statement with replace operation
  auto update_stmt = sqlgen::update<Note>(
    "content"_c.set("content"_c.replace("foo", "bar"))
  );

  // 3. Execute the update
  auto update_result = update_stmt(conn);
  if (!update_result) {
    throw std::runtime_error("Failed to execute update statement");
  }

  // 4. Read the updated data
  auto read_result = sqlgen::read<std::vector<Note>>(conn);
  if (!read_result) {
    throw std::runtime_error("Failed to read updated data");
  }

  std::vector<Note> updated_notes = *read_result;

  // 5. Transform the data to UpdatedNote format
  std::vector<UpdatedNote> result;
  for (const auto& note : updated_notes) {
    result.push_back(UpdatedNote{
      .note_id = note.note_id,
      .updated_content = note.content
    });
  }

  return result;
}

